    digits = args[0]
    if not isinstance(output, list):
        return False
    mapping = {'2': 'abc', '3': 'def', '4': 'ghi', '5': 'jkl', '6': 'mno', '7': 'pqrs', '8': 'tuv', '9': 'wxyz'}
    if digits == '':
        return output == []
    expected = ['']
    for d in digits:
        letters = mapping.get(d)
        if letters is None:
            return False
        expected = [prefix + ch for prefix in expected for ch in letters]
    correct = set(expected)
    seen = set()
    for combo in output:
        if not isinstance(combo, str):
            return False
        if combo not in correct:
            return False
        if combo in seen:
            return False
        seen.add(combo)
    return seen == correct

