function validate(args, output) {
    const digits = args[0];
    if (!Array.isArray(output)) return false;
    const mapping = {'2': 'abc', '3': 'def', '4': 'ghi', '5': 'jkl', '6': 'mno', '7': 'pqrs', '8': 'tuv', '9': 'wxyz'};
    if (digits === '') return output.length === 0;
    let expected = [''];
    for (const d of digits) {
        const letters = mapping[d];
        if (letters === undefined) return false;
        const next = [];
        for (const prefix of expected) for (const ch of letters) next.push(prefix + ch);
        expected = next;
    }
    const correct = new Set(expected);
    const seen = new Set();
    for (const combo of output) {
        if (typeof combo !== 'string') return false;
        if (!correct.has(combo)) return false;
        if (seen.has(combo)) return false;
        seen.add(combo);
    }
    if (seen.size !== correct.size) return false;
    for (const c of correct) if (!seen.has(c)) return false;
    return true;
}

